Based on the reference materials and detailed specifications, here's the complete implementation for the required functions:

```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Use sqlgen::write to insert records
  auto write_op = sqlgen::write(records);
  write_op(conn).value();
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Use sqlgen::delete_from with where condition
  auto delete_op = sqlgen::delete_from<get_table_type(table_name)> 
                   | sqlgen::where("id"_c == record_id);
  delete_op(conn).value();
}

template<typename T>
void modify_eas_records_by_id(const std::string& table_name,
                               const int& record_id,
                               const std::string& col_name,
                               const T& new_value) {
  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Use sqlgen::update with set and where conditions
  auto update_op = sqlgen::update<get_table_type(table_name)>(
      "col_name"_c.set(new_value)
  ) | sqlgen::where("id"_c == record_id);
  update_op(conn).value();
}

// Helper function to map table name to struct type
template<std::string _name>
struct TableType;

template<>
struct TableType<"Student"> {
  using Type = Student;
};

template<>
struct TableType<"Course"> {
  using Type = Course;
};

template<>
struct TableType<"Score"> {
  using Type = Score;
};

template<>
struct TableType<"Major"> {
  using Type = Major;
};

template<std::string _name>
using get_table_type = typename TableType<_name>::Type;
```

## Explanation:

1. **`add_eas_records`**:
   - Uses `sqlgen::sqlite::connect` to establish database connection
   - Uses `sqlgen::write` to insert records into the specified table
   - The template parameter `T` should be the struct type corresponding to the table (e.g., `Student`, `Course`)

2. **`delete_eas_records_by_id`**:
   - Uses `sqlgen::delete_from` with a where condition to delete records by ID
   - The `get_table_type` helper maps the table name string to the corresponding struct type
   - Uses the `"id"_c` column literal to reference the primary key

3. **`modify_eas_records_by_id`**:
   - Uses `sqlgen::update` to create an update statement
   - Uses `set` to specify the column to update and its new value
   - Uses `where` to filter by the primary key ID
   - The template parameter `T` should be the type of the new value

The implementation follows the sqlgen library patterns shown in the reference materials, using the fluent interface with `|` operators to chain operations together.

