  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // 2. Build the query using sqlgen's fluent interface
  auto query = sqlgen::read<std::vector<OrderView>>
             | sqlgen::inner_join<Customer, "t2">("customer_id"_t1 == "customer_id"_t2)
             | sqlgen::where("total_amount"_t1 > 1000.0)
             | sqlgen::order_by("total_amount"_t1.desc());

  // 3. Execute the query and return results
  return query(conn).value();
}

}  // namespace query_high_value_orders
