 * Returns: std::vector<UpdatedNote>.
 */
std::vector<UpdatedNote> replace_text_in_notes() {
  // 1. Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // 2. Create update statement using sqlgen::update API
  // 3. Use set() method to specify the replacement operation
  // 4. Execute the update statement on the connection
  auto update_result = (sqlgen::update<Note>(Note::content.set("bar")))(conn);
  if (!update_result) {
    throw std::runtime_error("Update operation failed");
  }

  // 5. Read the updated notes from the database
  auto read_result = sqlgen::read<std::vector<Note>>(conn);
  if (!read_result) {
    throw std::runtime_error("Failed to read updated notes");
  }
  auto updated_notes = read_result.value();

  // 6. Convert to UpdatedNote structure
  std::vector<UpdatedNote> result;
  for (const auto& note : updated_notes) {
    result.push_back(UpdatedNote{
        .note_id = note.note_id,
        .updated_content = note.content
    });
  }

  return result;
}

