namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false; // Connection failed
  }
  auto conn = *conn_result;

  // 2. Create tables with proper constraints
  auto create_parent = sqlgen::create_table<Parent>;
  auto create_child = sqlgen::create_table<Child>;

  auto create_result = conn->execute(create_parent.to_sql());
  if (!create_result) {
    return false; // Table creation failed
  }

  create_result = conn->execute(create_child.to_sql());
  if (!create_result) {
    return false; // Table creation failed
  }

  // 3. Insert parent and child records with same parent_id
  Parent parent{1, "Test Parent"};
  Child child{1, 1, "Test Child Note"};

  auto insert_parent = sqlgen::insert(parent);
  auto insert_child = sqlgen::insert(child);

  auto insert_result = conn->execute(insert_parent.to_sql());
  if (!insert_result) {
    return false; // Parent insertion failed
  }

  insert_result = conn->execute(insert_child.to_sql());
  if (!insert_result) {
    return false; // Child insertion failed
  }

  // 4. Delete parent and verify child deletion
  auto delete_parent = sqlgen::delete_from<Parent> | sqlgen::where("parent_id"_c == 1);
  auto delete_result = conn->execute(delete_parent.to_sql());
  if (!delete_result) {
    return false; // Delete operation failed
  }

  // 5. Verify child was deleted
  auto read_child = sqlgen::read<std::vector<Child>> | sqlgen::where("parent_id"_c == 1);
  auto child_result = conn->execute(read_child.to_sql());
  if (!child_result) {
    return false; // Read operation failed
  }

  // Check if child still exists
  auto child_vec = child_result.value();
  return child_vec.empty(); // Returns true if child was deleted, false otherwise
}

}  // namespace cascade_delete_demo
