               | inner_join<Sales>("product_id"_c == "product_id"_c)
               | group_by("product_id"_c, "product_name"_c, "category"_c)
               | order_by("total_sales"_c.desc())
               | limit(limit_count);

  // Execute the query and return results
  return query(conn);
}

}  // namespace get_top_products
```

